React events are named using camelCase and pass functions as event handlers.

**Basic Event Handler:**
```jsx
function Button() {
  const handleClick = () => {
    console.log('Button clicked!');
  };

  return <button onClick={handleClick}>Click me</button>;
}
```

**Event Object:**
```jsx
function Form() {
  const handleSubmit = (event) => {
    event.preventDefault(); // Prevent default form submission
    console.log('Form submitted');
  };

  return <form onSubmit={handleSubmit}>...</form>;
}
```

**Passing Arguments:**
```jsx
function Button() {
  const handleClick = (name) => {
    console.log(`Hello, ${name}!`);
  };

  return <button onClick={() => handleClick('John')}>Click me</button>;
}
```

**Common Events:**
```jsxn// Click events
<button onClick={handleClick}>Click</button>

// Change events
<input onChange={handleChange} />

// Submit events
<form onSubmit={handleSubmit}>...</form>

// Focus events
<input onFocus={handleFocus} onBlur={handleBlur} />

// Mouse events
<div onMouseEnter={handleMouseEnter} onMouseLeave={handleMouseLeave} />
```

**Event Differences from HTML:**
- React events are named with camelCase
- React events prevent default behavior differently
- React events are synthetic (cross-browser)

React wraps native browser events into synthetic events for cross-browser compatibility.

**Event Properties:**
```jsx
function handleClick(event) {
  console.log('Event type:', event.type);
  console.log('Target:', event.target);
  console.log('Current target:', event.currentTarget);
  console.log('Client coordinates:', event.clientX, event.clientY);
  console.log('Key pressed:', event.key);
}
```

**Common Event Methods:**
```jsx
function Form() {
  const handleSubmit = (event) => {
    event.preventDefault(); // Prevent default behavior
    event.stopPropagation(); // Stop event bubbling
  };

  return <form onSubmit={handleSubmit}>...</form>;
}
```

**Event Bubbling:**
```jsxnfunction Parent() {
  const handleParentClick = () => {
    console.log('Parent clicked');
  };

  const handleChildClick = (event) => {
    event.stopPropagation(); // Stop bubbling to parent
    console.log('Child clicked');
  };

  return (
    <div onClick={handleParentClick}>
      <button onClick={handleChildClick}>Click me</button>
    </div>
  );
}
```

**Keyboard Events:**
```jsxnfunction Input() {
  const handleKeyDown = (event) => {
    if (event.key === 'Enter') {
      console.log('Enter key pressed');
    }
  };

  return <input onKeyDown={handleKeyDown} />;
}
```

Controlled components have their form data controlled by React state.

**Text Input:**
```jsx
function TextInput() {
  const [value, setValue] = useState('');

  const handleChange = (event) => {
    setValue(event.target.value);
  };

  return (
    <input
      type="text"
      value={value}
      onChange={handleChange}
      placeholder="Enter text"
    />
  );
}
```

**Textarea:**
```jsx
function TextArea() {
  const [value, setValue] = useState('');

  const handleChange = (event) => {
    setValue(event.target.value);
  };

  return (
    <textarea
      value={value}
      onChange={handleChange}
      placeholder="Enter message"
    />
  );
}
```

**Select Dropdown:**
```jsx
function Select() {
  const [value, setValue] = useState('');

  const handleChange = (event) => {
    setValue(event.target.value);
  };

  return (
    <select value={value} onChange={handleChange}>
      <option value="">Choose an option</option>
      <option value="option1">Option 1</option>
      <option value="option2">Option 2</option>
    </select>
  );
}
```

**Checkbox:**
```jsx
function Checkbox() {
  const [checked, setChecked] = useState(false);

  const handleChange = (event) => {
    setChecked(event.target.checked);
  };

  return (
    <label>
      <input
        type="checkbox"
        checked={checked}
        onChange={handleChange}
      />
      Accept terms
    </label>
  );
}
```

**Radio Buttons:**
```jsx
function RadioGroup() {
  const [selected, setSelected] = useState('option1');

  const handleChange = (event) => {
    setSelected(event.target.value);
  };

  return (
    <div>
      <label>
        <input
          type="radio"
          value="option1"
          checked={selected === 'option1'}
          onChange={handleChange}
        />
        Option 1
      </label>
      <label>
        <input
          type="radio"
          value="option2"
          checked={selected === 'option2'}
          onChange={handleChange}
        />
        Option 2
      </label>
    </div>
  );
}
```

Validate form input to ensure data quality and user experience.
```jsx
function LoginForm() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [errors, setErrors] = useState({});

  const validate = () => {
    const newErrors = {};

    if (!email) {
      newErrors.email = 'Email is required';
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      newErrors.email = 'Email is invalid';
    }

    if (!password) {
      newErrors.password = 'Password is required';
    } else if (password.length < 6) {
      newErrors.password = 'Password must be at least 6 characters';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (event) => {
    event.preventDefault();

    if (validate()) {
      console.log('Form is valid');
      // Submit form
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <input
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
        {errors.email && <span className="error">{errors.email}</span>}
      </div>
      <div>
        <input
          type="password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        {errors.password && <span className="error">{errors.password}</span>}
      </div>
      <button type="submit">Submit</button>
    </form>
  );
}
```

**Real-time Validation:**
```jsx
function InputWithValidation() {
  const [value, setValue] = useState('');
  const [error, setError] = useState('');

  const handleChange = (event) => {
    const newValue = event.target.value;
    setValue(newValue);

    if (newValue.length < 3) {
      setError('Must be at least 3 characters');
    } else {
      setError('');
    }
  };

  return (
    <div>
      <input value={value} onChange={handleChange} />
      {error && <span className="error">{error}</span>}
    </div>
  );
}
```

Popular libraries for handling forms in React.

**Formik (Popular Choice):**
```jsx
import { Formik, Form, Field, ErrorMessage } from 'formik';

function MyForm() {
  return (
    <Formik
      initialValues={{ email: '', password: '' }}
      validate={values => {
        const errors = {};
        if (!values.email) errors.email = 'Required';
        return errors;
      }}
      onSubmit={(values, { setSubmitting }) => {
        console.log(values);
        setSubmitting(false);
      }}
    >
      <Form>
        <Field type="email" name="email" />
        <ErrorMessage name="email" component="div" />
        <Field type="password" name="password" />
        <ErrorMessage name="password" component="div" />
        <button type="submit">Submit</button>
      </Form>
    </Formik>
  );
}
```

**React Hook Form (Performance):**
```jsx
import { useForm } from 'react-hook-form';

function MyForm() {
  const { register, handleSubmit, formState: { errors } } = useForm();

  const onSubmit = data => console.log(data);

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <input {...register('email', { required: true })} />
      {errors.email && <span>This field is required</span>}
      <input type="password" {...register('password', { required: true })} />
      {errors.password && <span>This field is required</span>}
      <button type="submit">Submit</button>
    </form>
  );
}
```

**When to Use Libraries:**
- Complex forms with many fields
- Need for validation
- Performance requirements
- Team familiarity
